import app from 'flarum/admin/app';

// The Hero Studio: a simple, complete settings form. The icon is a free-text
// Font Awesome field (type any class — not a fixed preset list).
app.initializers.add('ernestdefoe-hero-builder', () => {
  const K = 'ernestdefoe-hero-builder';
  const t = k => app.translator.trans("".concat(K, ".admin.").concat(k));
  app.extensionData.for(K).registerSetting({
    setting: "".concat(K, ".enabled"),
    type: 'boolean',
    label: t('enabled')
  }).registerSetting({
    setting: "".concat(K, ".title"),
    type: 'text',
    label: t('title'),
    placeholder: t('title_placeholder')
  }).registerSetting({
    setting: "".concat(K, ".subtitle"),
    type: 'text',
    label: t('subtitle')
  }).registerSetting({
    setting: "".concat(K, ".icon"),
    type: 'text',
    label: t('icon'),
    help: t('icon_help'),
    placeholder: 'fas fa-meteor'
  }).registerSetting({
    setting: "".concat(K, ".c1"),
    type: 'text',
    label: t('c1'),
    placeholder: '#7c3aed'
  }).registerSetting({
    setting: "".concat(K, ".c2"),
    type: 'text',
    label: t('c2'),
    placeholder: '#ec4899'
  }).registerSetting({
    setting: "".concat(K, ".image"),
    type: 'text',
    label: t('image'),
    help: t('image_help')
  }).registerSetting({
    setting: "".concat(K, ".showStats"),
    type: 'boolean',
    label: t('show_stats')
  });
});